# ❌ WRONG - Object types need subfield selection
query FindScene($id: ID!) {
  findScene(id: $id) {
    urls          # ERROR: must select subfields
    images        # ERROR: must select subfields
  }
}

# ✅ CORRECT - Select specific subfields
query FindScene($id: ID!) {
  findScene(id: $id) {
    urls { url }
    images { url }
    performers {
      performer {
        images { url }  # Nested objects too
      }
    }
  }
}

# ❌ WRONG - Field names don't match schema
query SearchScene($term: String!) {
  searchScene(term: $term) {
    urls { view }           # ERROR: field 'view' doesn't exist
    site { name }           # ERROR: field 'site' doesn't exist
    performers {
      performer {
        image               # ERROR: field 'image' doesn't exist
      }
    }
  }
}

# ✅ CORRECT - Use actual schema field names
query SearchScene($term: String!) {
  searchScene(term: $term) {
    urls { url }            # Correct field name
    studio { name }         # 'studio' not 'site'
    performers {
      performer {
        images { url }      # 'images' (array) not 'image'
      }
    }
  }
}
